int
read_objects(FILE *fp, F_compound *obj)
{
	F_ellipse	*e, *le = NULL;
	F_line		*l, *ll = NULL;
	F_text		*t, *lt = NULL;
	F_spline	*s, *ls = NULL;
	F_arc		*a, *la = NULL;
	F_compound	*c, *lc = NULL;
	bool		objects = false;
	int		object, coord_sys;
	int		line_no;
	int		gif_colnum = 0;
	char		*line;
	char		buf[16];
	size_t		line_len = 256;

	/* Get the 15 chars of the first line. Use fgets(), because get_line() would store the line as a comment */
	if (fgets(buf, sizeof buf, fp) == NULL) {
		put_msg("Could not read input file.");
		return -1;
	}

	/* check for embedded '\0' */
	if (strlen(buf) < sizeof buf - 1 && buf[strlen(buf) - 1] != '\n') {
		put_msg("ASCII NUL ('\\0') character within the first line.");
		exit(EXIT_FAILURE);
	/* seek to the end of the first line (the only place, where '\0's are tolerated) */
	} else if (buf[strlen(buf) - 1] != '\n') {
		int c;
		do c = fgetc(fp);
		while (c != '\n' && c != EOF);
	}

	if (strncmp(buf, "#FIG ", 5)) {
		put_msg("Incorrect format string in first line of input file.");
		return -1;
	}

	v2_flag = (!strncmp(buf, "#FIG 2", 6) || !strncmp(buf, "#FIG 3", 6));
	v21_flag = (!strncmp(buf, "#FIG 2.1", 8) || !strncmp(buf, "#FIG 3", 6));
	v30_flag = (!strncmp(buf, "#FIG 3", 6) || !strncmp(buf, "#FIG 2.2", 8));
	v32_flag = (!strncmp(buf, "#FIG 3.2", 8));
	if (strncmp(&buf[5], PACKAGE_VERSION, 3) > 0) {
		put_msg("Fig file format (%s) newer than this version of fig2dev (%s), exiting", &buf[5], PACKAGE_VERSION);
		exit(EXIT_FAILURE);
	}

	if ((v2_flag | v21_flag | v30_flag | v32_flag) == 0 && strncmp(buf, "#FIG 1.4", 8)) {
		put_msg("Cannot determine fig file format from string '%s'.", &buf[5]);
		exit(EXIT_FAILURE);
	}

	if ((line = malloc(line_len)) == NULL) {
		put_msg(Err_mem);
		return -1;
	}

	line_no = 1;
	if (v30_flag) {
		if (get_line(fp, &line, &line_len, &line_no) < 0) {
			put_msg("File is truncated at landscape/portrait specification.");
			free(line);
			return -1;
		}
		if (!orientspec)
			landscape = !strncasecmp(line, "land", 4);

		if (get_line(fp, &line, &line_len, &line_no) < 0) {
			put_msg("File is truncated at metric/inches or centering specification.");
			free(line);
			return -1;
		}

		if ((strncasecmp(line, "center", 6) == 0) || (strncasecmp(line, "flush", 5) == 0)) {
			if (!centerspec)
				center = strncasecmp(line, "flush", 5);
			if (get_line(fp, &line, &line_len, &line_no) < 0) {
				put_msg("File is truncated at metric/inches specification.");
				free(line);
				return -1;
			}
		}
		if (strncasecmp(line, "metric", 6) == 0) {
			metric = 1;
		} else {
			metric = 0;
		}

		if (v32_flag) {
			if (get_line(fp, &line, &line_len, &line_no) < 0) {
				put_msg("File is truncated at paper size specification.");
				free(line);
				return -1;
			}
			if (!paperspec) {
				char *p;
				if ((p = strchr(line, ' '))) *p = '\0';
				if (strlen(line) + 1 > sizeof papersize) {
					put_msg("Invalid paper size specification at line %d: %s", line_no, line);
					free(line);
					return -1;
				}
				strcpy(papersize, line);
			}

			if (get_line(fp, &line, &line_len, &line_no) < 0) {
				put_msg("File is truncated at magnification specification.");
				free(line);
				return -1;
			}
			if (!magspec) {
				mag = atof(line)/100.0;
				if (mag <= 0.) mag = 1.;
				fontmag = mag;
			}

			if (get_line(fp, &line, &line_len, &line_no) < 0) {
				put_msg("File is truncated at multiple page specification.");
				free(line);
				return -1;
			}
			if (!multispec)
				multi_page = (strncasecmp(line, "multiple", 8) == 0);

			if (get_line(fp, &line, &line_len, &line_no) < 0) {
				put_msg("File is truncated at transparent color specification.");
				free(line);
				return -1;
			}
			if (!transspec) {
				gif_colnum = atoi(line);
				if (gif_colnum < -3) {
					put_msg("Invalid color number for transparent color.");
					free(line);
					return -1;
				}
				if (gif_colnum < NUM_STD_COLS && gif_colnum >= 0)
					strcpy(gif_transparent, Fig_color_names[gif_colnum]);
			}
		}
	} else {
		metric = 0;
	}

	if (!v32_flag) {
		if (!paperspec) {
			if (metric) strcpy(papersize, "A4"); else strcpy(papersize, "Letter");
		}
	}

	if (get_line(fp, &line, &line_len, &line_no) < 0) {
		put_msg("File is truncated at resolution specification.");
		free(line);
		return -1;
	}
	if (sscanf(line, "%lf%d", &ppi, &coord_sys) != 2) {
		put_msg("Incomplete resolution information at line %d.", line_no);
		free(line);
		return -1;
	}
	if (ppi <= 1.) {
		put_msg("Invalid resolution information (%g) at line %d.", ppi, line_no);
		free(line);
		return -1;
	}

	THICK_SCALE = ppi/80;
	obj->comments = attach_comments();

	while (get_line(fp, &line, &line_len, &line_no) > 0) {
		if (sscanf(line, "%d", &object) != 1) {
			put_msg("Incorrect format at line %d.", line_no);
			free(line);
			return -1;
		}
		switch (object) {
			case OBJ_COLOR_DEF:
				if (objects) {
					put_msg("Color definitions must come before other objects (line %d).", line_no);
					free(line);
					return -1;
				}
				read_colordef(line, line_no);
				break;
			case OBJ_POLYLINE:
				if ((l = read_lineobject(fp, &line, &line_len, &line_no)) == NULL) {
					free(line);
					return -1;
				}
				if (ll) ll = (ll->next = l); else ll = obj->lines = l;
				objects = true;
				break;
			case OBJ_SPLINE:
				if ((s = read_splineobject(fp, &line, &line_len, &line_no)) == NULL) {
					free(line);
					return -1;
				}
				if (v32_flag) {
					if (ll) ll = (ll->next = (F_line *) s); else ll = obj->lines = (F_line *) s;
					objects = true;
					break;
				}
				if (ls) ls = (ls->next = s); else ls = obj->splines = s;
				objects = true;
				break;
			case OBJ_ELLIPSE:
				if ((e = read_ellipseobject(line, line_no)) == NULL) {
					free(line);
					return -1;
				}
				if (le) le = (le->next = e); else le = obj->ellipses = e;
				objects = true;
				break;
			case OBJ_ARC:
				if ((a = read_arcobject(fp, &line, &line_len, &line_no)) == NULL) {
					free(line);
					return -1;
				}
				if (la) la = (la->next = a); else la = obj->arcs = a;
				objects = true;
				break;
			case OBJ_TEXT:
				if ((t = read_textobject(fp, &line, &line_len, &line_no)) == NULL) {
					free(line);
					return -1;
				}
				if (lt) lt = (lt->next = t); else lt = obj->texts = t;
				objects = true;
				break;
			case OBJ_COMPOUND:
				if ((c = read_compoundobject(fp, &line, &line_len, &line_no)) == NULL) {
					free(line);
					return -1;
				}
				if (lc) lc = (lc->next = c); else lc = obj->compounds = c;
				objects = true;
				break;
			default:
				put_msg("Incorrect object code at line %d.", line_no);
				free(line);
				return -1;
		}
	}
	free(line);

	if (gif_colnum >= NUM_STD_COLS) {
		int i;
		if (num_usr_cols > MAX_USR_COLS) num_usr_cols = MAX_USR_COLS;
		for (i = 0; i < num_usr_cols; ++i)
			if (user_col_indx[i] == gif_colnum) break;
		if (i < num_usr_cols)
			sprintf(gif_transparent, "#%2x%2x%2x", user_colors[i].r, user_colors[i].g, user_colors[i].b);
	}

	if (feof(fp)) return 0; else return -3;
}
